  1→/**
  2→ * Rehype plugin to transform markdown file links (.md) to page routes
  3→ *
  4→ * Transforms:
  5→ *   ./path/to/file.md → ./path/to/file/
  6→ *   ./path/index.md → ./path/ (index.md becomes directory root)
  7→ *   ../path/file.md#anchor → ../path/file/#anchor
  8→ *   ./file.md?query=param → ./file/?query=param
  9→ *   /docs/absolute/path/file.md → {base}/absolute/path/file/
 10→ *
 11→ * For absolute paths starting with /docs/, the /docs prefix is stripped
 12→ * since the Astro site serves content from the docs directory as the root.
 13→ * The base path is prepended to absolute paths for subdirectory deployments.
 14→ *
 15→ * Affects relative links (./, ../) and absolute paths (/) - external links are unchanged
 16→ */
 17→
 18→import { visit } from 'unist-util-visit';
 19→
 20→/**
 21→ * Convert Markdown file links (.md) into equivalent page route-style links.
 22→ *
 23→ * @param {Object} options - Plugin options
 24→ * @param {string} options.base - The base path to prepend to absolute URLs
 25→ * @returns {function} A HAST tree transformer
 26→ */
 27→export default function rehypeMarkdownLinks(options = {}) {
 28→  const base = options.base || '/';
 29→  // Normalize base: ensure it ends with / and doesn't have double slashes
 30→  const normalizedBase = base === '/' ? '' : base.endsWith('/') ? base.slice(0, -1) : base;
 31→
 32→  return (tree) => {
 33→    visit(tree, 'element', (node) => {
 34→      // Only process anchor tags with href
 35→      if (node.tagName !== 'a' || !node.properties?.href) {
 36→        return;
 37→      }
 38→
 39→      const href = node.properties.href;
 40→
 41→      if (typeof href !== 'string') {
 42→        return;
 43→      }
 44→
 45→      // Skip external links
 46→      if (href.includes('://') || href.startsWith('mailto:') || href.startsWith('tel:')) {
 47→        return;
 48→      }
 49→
 50→      // Only transform paths starting with ./, ../, or /
 51→      if (!href.startsWith('./') && !href.startsWith('../') && !href.startsWith('/')) {
 52→        return;
 53→      }
 54→
 55→      // Extract path portion (before ? and #) to check if it's a .md file
 56→      const firstDelimiter = Math.min(
 57→        href.indexOf('?') === -1 ? Infinity : href.indexOf('?'),
 58→        href.indexOf('#') === -1 ? Infinity : href.indexOf('#'),
 59→      );
 60→      const pathPortion = firstDelimiter === Infinity ? href : href.substring(0, firstDelimiter);
 61→
 62→      // Don't transform if path doesn't end with .md
 63→      if (!pathPortion.endsWith('.md')) {
 64→        return;
 65→      }
 66→
 67→      // Split the URL into parts: path, anchor, and query
 68→      let urlPath = pathPortion;
 69→      let anchor = '';
 70→      let query = '';
 71→
 72→      // Extract query string and anchor from original href
 73→      if (firstDelimiter !== Infinity) {
 74→        const suffix = href.substring(firstDelimiter);
 75→        const anchorInSuffix = suffix.indexOf('#');
 76→        if (suffix.startsWith('?')) {
 77→          if (anchorInSuffix !== -1) {
 78→            query = suffix.substring(0, anchorInSuffix);
 79→            anchor = suffix.substring(anchorInSuffix);
 80→          } else {
 81→            query = suffix;
 82→          }
 83→        } else {
 84→          anchor = suffix;
 85→        }
 86→      }
 87→
 88→      // Track if this was an absolute path
 89→      const isAbsolute = urlPath.startsWith('/');
 90→
 91→      // Strip /docs/ prefix from absolute paths
 92→      if (urlPath.startsWith('/docs/')) {
 93→        urlPath = urlPath.slice(5);
 94→      }
 95→
 96→      // Transform .md to /
 97→      if (urlPath.endsWith('/index.md')) {
 98→        urlPath = urlPath.replace(/\/index\.md$/, '/');
 99→      } else {
100→        urlPath = urlPath.replace(/\.md$/, '/');
101→      }
102→
103→      // Prepend base path to absolute URLs
104→      if (isAbsolute && normalizedBase) {
105→        urlPath = normalizedBase + urlPath;
106→      }
107→
108→      node.properties.href = urlPath + query + anchor;
109→    });
110→  };
111→}
