 1→/**
 2→ * Resolve the site's base URL using cascading environment defaults.
 3→ *
 4→ * Preference order: use SITE_URL if set; otherwise derive a GitHub Pages URL
 5→ * from GITHUB_REPOSITORY; otherwise use the local development URL.
 6→ *
 7→ * @returns {string} The resolved site URL.
 8→ */
 9→export function getSiteUrl() {
10→  // Explicit override (works in both local and GitHub Actions)
11→  if (process.env.SITE_URL) {
12→    return process.env.SITE_URL;
13→  }
14→
15→  // GitHub Actions: compute from repository context
16→  if (process.env.GITHUB_REPOSITORY) {
17→    const parts = process.env.GITHUB_REPOSITORY.split('/');
18→    if (parts.length !== 2 || !parts[0] || !parts[1]) {
19→      throw new Error(`Invalid GITHUB_REPOSITORY format: "${process.env.GITHUB_REPOSITORY}". Expected "owner/repo".`);
20→    }
21→    const [owner, repo] = parts;
22→    return `https://${owner}.github.io/${repo}`;
23→  }
24→
25→  // Local development: use dev server
26→  return 'http://localhost:3000';
27→}
