 1→/**
 2→ * Rehype plugin to prepend base path to absolute URLs
 3→ *
 4→ * Transforms:
 5→ *   /img/foo.png → /base/img/foo.png (when base is /base/)
 6→ *   /downloads/file.zip → /base/downloads/file.zip
 7→ *   /llms.txt → /base/llms.txt
 8→ *
 9→ * Only affects absolute paths (/) - relative paths and external URLs are unchanged.
10→ * Does NOT process .md links (those are handled by rehype-markdown-links).
11→ */
12→
13→import { visit } from 'unist-util-visit';
14→
15→/**
16→ * Create a rehype plugin that prepends the base path to absolute URLs.
17→ *
18→ * @param {Object} options - Plugin options
19→ * @param {string} options.base - The base path to prepend
20→ * @returns {function} A HAST tree transformer
21→ */
22→export default function rehypeBasePaths(options = {}) {
23→  const base = options.base || '/';
24→
25→  // Normalize base: ensure it ends with / and doesn't have double slashes
26→  const normalizedBase = base === '/' ? '/' : base.endsWith('/') ? base : base + '/';
27→
28→  return (tree) => {
29→    visit(tree, 'element', (node) => {
30→      // Process img tags with src attribute
31→      if (node.tagName === 'img' && node.properties?.src) {
32→        const src = node.properties.src;
33→
34→        if (typeof src === 'string' && src.startsWith('/') && !src.startsWith('//')) {
35→          if (normalizedBase !== '/' && !src.startsWith(normalizedBase)) {
36→            node.properties.src = normalizedBase + src.slice(1);
37→          }
38→        }
39→      }
40→
41→      // Process iframe tags with src attribute
42→      if (node.tagName === 'iframe' && node.properties?.src) {
43→        const src = node.properties.src;
44→
45→        if (typeof src === 'string' && src.startsWith('/') && !src.startsWith('//')) {
46→          if (normalizedBase !== '/' && !src.startsWith(normalizedBase)) {
47→            node.properties.src = normalizedBase + src.slice(1);
48→          }
49→        }
50→      }
51→
52→      // Process anchor tags with href attribute
53→      if (node.tagName === 'a' && node.properties?.href) {
54→        const href = node.properties.href;
55→
56→        if (typeof href !== 'string') {
57→          return;
58→        }
59→
60→        if (!href.startsWith('/') || href.startsWith('//')) {
61→          return;
62→        }
63→
64→        if (normalizedBase !== '/' && href.startsWith(normalizedBase)) {
65→          return;
66→        }
67→
68→        // Skip .md links - handled by rehype-markdown-links
69→        const firstDelimiter = Math.min(
70→          href.indexOf('?') === -1 ? Infinity : href.indexOf('?'),
71→          href.indexOf('#') === -1 ? Infinity : href.indexOf('#'),
72→        );
73→        const pathPortion = firstDelimiter === Infinity ? href : href.substring(0, firstDelimiter);
74→
75→        if (pathPortion.endsWith('.md')) {
76→          return;
77→        }
78→
79→        node.properties.href = normalizedBase + href.slice(1);
80→      }
81→    });
82→  };
83→}
