  1→/**
  2→ * Skill Forge Documentation - Custom Styles for Starlight
  3→ * Amber/orange forge-themed palette optimized for dark mode
  4→ */
  5→
  6→/* ============================================
  7→   COLOR PALETTE - Light Mode
  8→   ============================================ */
  9→:root {
 10→  --ai-banner-height: 2.75rem;
 11→  --sl-nav-height: 6.25rem; /* Base nav height (~3.5rem) + banner height (2.75rem) */
 12→
 13→  /* Primary accent colors - amber/orange forge palette */
 14→  --sl-color-accent-low: #fef3c7;
 15→  --sl-color-accent: #d97706;
 16→  --sl-color-accent-high: #92400e;
 17→
 18→  /* Text colors */
 19→  --sl-color-white: #1e293b;
 20→  --sl-color-gray-1: #334155;
 21→  --sl-color-gray-2: #475569;
 22→  --sl-color-gray-3: #64748b;
 23→  --sl-color-gray-4: #94a3b8;
 24→  --sl-color-gray-5: #cbd5e1;
 25→  --sl-color-gray-6: #e2e8f0;
 26→  --sl-color-black: #f8fafc;
 27→
 28→  /* Font settings */
 29→  --sl-font: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
 30→  --sl-text-base: 1rem;
 31→  --sl-line-height: 1.7;
 32→
 33→  /* Code highlighting */
 34→  --sl-color-bg-inline-code: rgba(217, 119, 6, 0.1);
 35→}
 36→
 37→/* ============================================
 38→   COLOR PALETTE - Dark Mode (Primary Focus)
 39→   ============================================ */
 40→:root[data-theme='dark'] {
 41→  /* Primary accent colors - amber/orange forge palette */
 42→  --sl-color-accent-low: #451a03;
 43→  --sl-color-accent: #f59e0b;
 44→  --sl-color-accent-high: #fbbf24;
 45→
 46→  /* Background colors */
 47→  --sl-color-bg: #1b1b1d;
 48→  --sl-color-bg-nav: #1b1b1d;
 49→  --sl-color-bg-sidebar: #1b1b1d;
 50→  --sl-color-hairline-light: rgba(245, 158, 11, 0.1);
 51→  --sl-color-hairline: rgba(245, 158, 11, 0.15);
 52→
 53→  /* Text colors */
 54→  --sl-color-white: #f8fafc;
 55→  --sl-color-gray-1: #e2e8f0;
 56→  --sl-color-gray-2: #cbd5e1;
 57→  --sl-color-gray-3: #94a3b8;
 58→  --sl-color-gray-4: #64748b;
 59→  --sl-color-gray-5: #475569;
 60→  --sl-color-gray-6: #334155;
 61→  --sl-color-black: #1b1b1d;
 62→
