209→/* ============================================
210→   CARDS
211→   ============================================ */
212→.card {
213→  border-radius: 12px;
214→  border: 2px solid var(--sl-color-gray-5);
215→  background-color: var(--sl-color-bg);
216→  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
