/* ============================================
   MERMAID DIAGRAM LIGHTBOX
   ============================================ */

/* Make diagrams look clickable */
pre.mermaid {
  cursor: zoom-in;
  transition: box-shadow 0.2s ease;
  border-radius: 8px;
}

pre.mermaid:hover {
  box-shadow: 0 0 0 2px var(--sl-color-accent);
}

/* Fullscreen overlay */
.mermaid-lightbox {
  position: fixed;
  inset: 0;
  z-index: 9999;
  display: flex;
  align-items: center;
  justify-content: center;
  background: rgba(0, 0, 0, 0.85);
  opacity: 0;
  visibility: hidden;
  transition:
    opacity 0.2s ease,
    visibility 0.2s ease;
  cursor: zoom-out;
}

.mermaid-lightbox.active {
  opacity: 1;
  visibility: visible;
}

.mermaid-lightbox-content {
  max-width: 90vw;
  max-height: 85vh;
  overflow: auto;
}

.mermaid-lightbox-content svg {
  width: 100%;
  height: auto;
  max-height: 85vh;
}

.mermaid-lightbox-close {
  position: absolute;
  top: 1rem;
  right: 1.5rem;
  background: none;
  border: none;
  color: #fff;
  font-size: 2.5rem;
  cursor: pointer;
  line-height: 1;
  opacity: 0.7;
  transition: opacity 0.15s ease;
}

.mermaid-lightbox-close:hover {
  opacity: 1;
}

.mermaid-lightbox-hint {
  position: absolute;
  bottom: 1.5rem;
  color: rgba(255, 255, 255, 0.5);
  font-size: 0.85rem;
  pointer-events: none;
}

