  visibility: hidden;
  transition:
    opacity 0.2s ease,
    visibility 0.2s ease;
  cursor: zoom-out;
}

.mermaid-lightbox.active {
  opacity: 1;
  visibility: visible;
}

.mermaid-lightbox-content {
  max-width: 90vw;
  max-height: 85vh;
  overflow: auto;
}

.mermaid-lightbox-content svg {
  width: 100%;
  height: auto;
  max-height: 85vh;
}

.mermaid-lightbox-close {
  position: absolute;
  top: 1rem;
  right: 1.5rem;
  background: none;
  border: none;
  color: #fff;
  font-size: 2.5rem;
  cursor: pointer;
  line-height: 1;
  opacity: 0.7;
  transition: opacity 0.15s ease;
}

.mermaid-lightbox-close:hover {
  opacity: 1;
}

.mermaid-lightbox-hint {
  position: absolute;
  bottom: 1.5rem;
  color: rgba(255, 255, 255, 0.5);
  font-size: 0.85rem;
  pointer-events: none;
}

